sp_widget.client_script:
api.controller = function (scmBreadcrumbsManager) {
    const c = this;

    c.showSpinner = true;

    c.server
        .get({
            action: "getRecord",
            transactionId: c.data.transactionId,
        })
        .then(function (response) {
            if (response.data.error) {
                console.error(response.data);
                spUtil.addErrorMessage(response.data.error);
                return;
            }
            c.number = response.data.number;
            c.showSpinner = false;
            scmBreadcrumbsManager.set(response.data.breadcrumbs);
        });
};

sp_widget.script:
(function () {
    const transactionId = input?.transactionId || gs.generateGUID();
    data.transactionId = transactionId;

    const logger = new Logger({
        transactionId: transactionId,
        source: "incident-details.server.js",
        includeTimeStamp: true,
        includeUserInfo: true,
        includeSessionId: true,
    });

    const number = String($sp.getParameter("scm_record_id"));
    if (!number) {
        logger.warn("No scm_record_id parameter provided");
        return;
    }

    if (input && input.action === "getRecord") {
        var grRecord = new GlideRecord("incident");
        grRecord.get("number", number);

        data.number = grRecord.number.getDisplayValue();
        data.breadcrumbs = [
            ...IncidentList.INCIDENT_MAIN_LIST_BREADCRUMB,
            {
                title: grRecord.number.getDisplayValue(),
                link: "?id=incident_details&scm_record_id=" + number,
            },
        ];
    }
})();
